function logout() {
  sessionStorage.removeItem(SESSION_KEY);
  applyAuthState();
}

function applyAuthState() {
  const sessionUser = sessionStorage.getItem(SESSION_KEY);
  const signedIn = sessionUser === state.user.name;
  const mustChangePassword = signedIn && state.user.mustChangePassword;
  document.body.classList.toggle("is-authenticated", signedIn && !mustChangePassword);
  document.querySelector("#landing-view").classList.toggle("active", !signedIn || mustChangePassword);
  document.querySelector("#login-form").classList.toggle("hidden", signedIn);
  document.querySelector("#signup-form").classList.toggle("active", false);
  document.querySelector("#forgot-password-form").classList.toggle("active", false);
  document.querySelector("#password-change-form").classList.toggle("active", mustChangePassword);
  if (mustChangePassword) {
    document.querySelector("#change-name").value = state.user.name;
    document.querySelector("#current-password").value = state.user.tempPassword;
  }
}

function openForm(type, item = null) {
  const dialog = document.querySelector("#item-dialog");
  document.querySelector("#item-type").value = type;
  document.querySelector("#dialog-title").textContent = item ? `Edit ${typeLabels[type]}` : `New ${typeLabels[type]}`;
  document.querySelector("#save-item-btn").dataset.id = item?.id || "";
  document.querySelector("#item-title").value = item?.title || "";
  document.querySelector("#item-date").value = item?.date || "";
  document.querySelector("#item-details").value = item?.details || "";
  document.querySelector("#item-link").value = item?.link || "";
  document.querySelector("#item-status").value = item?.status || "Not started";
  document.querySelector("#link-field").style.display = type === "resource" ? "grid" : "none";
  document.querySelector("#status-field").style.display = type === "subject" ? "grid" : "none";
  document.querySelector("#details-label").textContent = type === "subject" ? "Learning plan" : "Details";
  dialog.showModal();
}

function saveItem() {
  const type = document.querySelector("#item-type").value;
  const collection = collectionFor(type);
  const existingId = document.querySelector("#save-item-btn").dataset.id;
  const item = {
    id: existingId || crypto.randomUUID(),
    title: document.querySelector("#item-title").value.trim(),
    date: document.querySelector("#item-date").value,
    status: document.querySelector("#item-status").value,
    details: document.querySelector("#item-details").value.trim(),
    link: document.querySelector("#item-link").value.trim(),
    updatedAt: new Date().toISOString()
  };

  if (existingId) {
    const index = collection.findIndex((entry) => entry.id === existingId);
    collection[index] = item;
  } else {
    collection.unshift(item);
  }

  persist();
  document.querySelector("#item-dialog").close();
  render();
}

function submitQuizAttempt(event) {
  event.preventDefault();
  const form = event.currentTarget;
  const test = state.tests.find((entry) => entry.id === form.dataset.testId);
  const section = activeGateDaSections().find((entry) => entry.id === test?.sectionId);
  const quiz = section?.reviewQuiz;
  if (!test || !quiz) return;

  const formData = new FormData(form);
  const answers = quiz.questions.map((question) => {
    const selected = formData.get(question.id);
    return {
      questionId: question.id,
      selected,
      correctAnswer: question.answer,
      isCorrect: selected === question.answer,
      tags: question.tags,
      kind: question.kind,
      targetConcept: question.targetConcept || question.tags[0],
      prereqsUsed: question.prereqsUsed || question.tags.slice(1),
      difficulty: question.difficulty || question.tags.length,
      gateWeight: question.gateWeight || "medium"
    };
  });
  const score = answers.filter((answer) => answer.isCorrect).length;
  const total = quiz.questions.length;
  const feedback = buildQuizFeedback(answers, quiz, section);
  const attempt = {
    id: `attempt-${quiz.id}-${Date.now()}`,
    userId: state.user.id,
    testId: test.id,
    quizId: quiz.id,
    sectionId: section.id,
    subject: section.subject,
    title: quiz.title,
    date: new Date().toISOString(),
    score,
    total,
    percent: Math.round((score / total) * 100),
    answers,
    feedback
  };

  state.quizAttempts.push(attempt);
  state.feedback.unshift({
    id: `feedback-${attempt.id}`,
    title: `${quiz.title}: Attempt ${state.quizAttempts.filter((entry) => entry.quizId === quiz.id).length}`,
    date: new Date().toISOString().slice(0, 10),
    details: `${score}/${total} (${attempt.percent}%). ${feedback.summary} Strong: ${feedback.strong.join(", ") || "none yet"}. Review: ${feedback.weak.join(", ") || "none flagged"}. ${feedback.report?.nextAction || ""}`,
    attemptId: attempt.id,
    updatedAt: attempt.date
  });

  activeTestId = null;
  persist();
  render();
}

function buildQuizFeedback(answers, quiz = null, section = null) {
  const conceptScores = {};
  answers.forEach((answer) => {
    const scoredConcepts = new Set([
      answer.targetConcept,
      ...(answer.prereqsUsed || []),
      ...(answer.tags || [])
    ].filter(Boolean));
    scoredConcepts.forEach((concept) => {
      if (!conceptScores[concept]) conceptScores[concept] = { correct: 0, total: 0 };
      conceptScores[concept].total += 1;
      if (answer.isCorrect) conceptScores[concept].correct += 1;
    });
  });

  const strong = [];
  const weak = [];
  const developing = [];
  Object.entries(conceptScores).forEach(([tag, score]) => {
    const percent = score.correct / score.total;
    if (percent >= 0.8) strong.push(conceptLabel(tag));
    else if (percent < 0.6) weak.push(conceptLabel(tag));
    else developing.push(conceptLabel(tag));
  });

  const missedMixed = answers.filter((answer) => !answer.isCorrect && answer.tags.length > 1).length;
  const summary = missedMixed
    ? "Mixed-concept misses suggest practising event translation before choosing a counting method."
    : "Misses are mostly isolated concept checks; review the flagged concepts and retake.";

  const report = buildQuizFeedbackReport({ answers, quiz, section, conceptScores, strong, developing, weak });
  return { summary: report?.summary || summary, strong, developing, weak, conceptScores, report };
}

function buildQuizFeedbackReport({ answers, quiz, section, conceptScores, strong, developing, weak }) {
  const graph = conceptGraphForSection(section);
  if (!graph) return null;

  const conceptMastery = Object.fromEntries(
    Object.entries(conceptScores).map(([concept, score]) => {
      const percent = score.total ? Math.round((score.correct / score.total) * 100) : 0;
      return [concept, {
        concept,
        label: conceptGraphLabel(graph, concept),
        correct: score.correct,
        total: score.total,
        percent,
        status: percent >= 80 ? "strong" : percent >= 60 ? "developing" : "weak"
      }];
    })
  );

  const missed = answers.filter((answer) => !answer.isCorrect);
  const prerequisiteBreaks = missed.map((answer) => {
    const candidateConcepts = [answer.targetConcept, ...(answer.prereqsUsed || [])].filter(Boolean);
    const likelyGap = candidateConcepts.find((concept) => (conceptMastery[concept]?.percent ?? 0) < 70) || answer.targetConcept;
    const prereqLabels = (answer.prereqsUsed || []).map((concept) => conceptGraphLabel(graph, concept));
    return {
      questionId: answer.questionId,
      targetConcept: answer.targetConcept,
      targetLabel: conceptGraphLabel(graph, answer.targetConcept),
      prereqsUsed: answer.prereqsUsed || [],
      prereqLabels,
      difficulty: answer.difficulty || 1,
      likelyGap,
      likelyGapLabel: conceptGraphLabel(graph, likelyGap),
      evidence: `Missed ${answer.questionId}, a difficulty ${answer.difficulty || 1} question mixing ${[conceptGraphLabel(graph, answer.targetConcept), ...prereqLabels].join(" + ")}.`
    };
  });

  const recommendedWork = buildRecommendedWork(graph, conceptMastery, prerequisiteBreaks);
  const readiness = estimateGateReadiness({ answers, conceptMastery, graph });
  const weakLabels = weak.length ? weak : recommendedWork.map((item) => item.label).slice(0, 3);
  const summary = recommendedWork.length
    ? `Main repair area: ${recommendedWork[0].label}. ${readiness.label}`
    : `${graph.chapterTitle} looks stable. ${readiness.label}`;

  return {
    chapterId: graph.chapterId,
    chapterTitle: graph.chapterTitle,
    quizId: quiz?.id || "",
    verdict: readiness.verdict,
    score: answers.filter((answer) => answer.isCorrect).length,
    maxScore: answers.length,
    readiness,
    summary,
    strengths: strong,
    developing,
    weaknesses: weakLabels,
    conceptMastery,
    prerequisiteBreaks,
    recommendedWork,
    nextQuizPlan: buildNextQuizPlan(recommendedWork, graph),
    nextAction: recommendedWork[0]
      ? `Next: ${recommendedWork[0].action}`
      : graph.stableNextAction || `Next: try a mixed ${graph.chapterTitle} review set at difficulty 3.`
  };
}

function conceptGraphForSection(section) {
  if (section?.id === "gate-da-linear-algebra-vector-spaces-coordinates") return linearAlgebraVectorSpacesConceptGraph();
  if (section?.id === "gate-da-linear-algebra-transformations-matrices") return linearAlgebraTransformationsConceptGraph();
  if (section?.id === "gate-da-linear-algebra-rank-nullity-systems") return linearAlgebraRankNullityConceptGraph();
  if (section?.id === "gate-da-linear-algebra-orthogonal-projections") return linearAlgebraOrthogonalProjectionsConceptGraph();
  if (section?.id === "gate-da-linear-algebra-determinants-trace-identities") return linearAlgebraDeterminantsTraceConceptGraph();
  if (section?.id === "gate-da-linear-algebra-eigenvalues-eigenvectors") return linearAlgebraEigenvaluesConceptGraph();
  if (section?.id === "gate-da-linear-algebra-symmetric-quadratic-forms") return linearAlgebraSymmetricQuadraticFormsConceptGraph();
  if (section?.id === "gate-da-linear-algebra-special-matrices") return linearAlgebraSpecialMatricesConceptGraph();
  if (section?.id === "gate-da-linear-algebra-svd-singular-values") return linearAlgebraSvdSingularValuesConceptGraph();
  if (section?.id === "gate-da-linear-algebra-least-squares-ridge") return linearAlgebraLeastSquaresRidgeConceptGraph();
  if (section?.id === "gate-da-linear-algebra-covariance-pca") return linearAlgebraCovariancePcaConceptGraph();
  if (section?.id === "gate-da-linear-algebra-data-synthesis") return linearAlgebraDataSynthesisConceptGraph();
  if (section?.id === "gate-da-linear-algebra-cumulative-drill") return linearAlgebraCumulativeDrillConceptGraph();
  if (section?.id === "gate-da-probability-foundations") return probabilityFoundationConceptGraph();
  if (section?.id === "gate-da-conditional-probability") return conditionalProbabilityConceptGraph();
  if (section?.id === "gate-da-random-variables-expectation") return randomVariablesExpectationConceptGraph();
  if (section?.id === "gate-da-variance-standard-deviation-tail-bounds") return varianceTailBoundsConceptGraph();
  if (section?.id === "gate-da-joint-distributions") return jointDistributionsConceptGraph();
  if (section?.id === "gate-da-covariance-correlation") return covarianceCorrelationConceptGraph();
  if (section?.id === "gate-da-conditional-expectation-variance") return conditionalExpectationConceptGraph();
  if (section?.id === "gate-da-continuous-distributions-order-statistics") return continuousDistributionsOrderStatisticsConceptGraph();
  return null;
}

function conceptGraphLabel(graph, concept) {
  return graph?.nodes?.[concept]?.label || conceptLabel(concept);
}

function buildRecommendedWork(graph, conceptMastery, prerequisiteBreaks) {
  const priority = {};
  prerequisiteBreaks.forEach((entry) => {
    const concept = entry.likelyGap || entry.targetConcept;
    priority[concept] = (priority[concept] || 0) + 2 + Math.max(0, (entry.difficulty || 1) - 1);
    (entry.prereqsUsed || []).forEach((prereq) => {
      if ((conceptMastery[prereq]?.percent ?? 100) < 70) priority[prereq] = (priority[prereq] || 0) + 1;
    });
  });

  Object.values(conceptMastery).forEach((entry) => {
    if (entry.percent < 60) priority[entry.concept] = (priority[entry.concept] || 0) + 2;
    else if (entry.percent < 80) priority[entry.concept] = (priority[entry.concept] || 0) + 1;
  });

  return Object.entries(priority)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 4)
    .map(([concept, weight], index) => ({
      concept,
      label: conceptGraphLabel(graph, concept),
      priority: index === 0 ? "high" : weight >= 3 ? "medium" : "low",
      material: graph.nodes[concept]?.repairMaterial || `Review ${conceptGraphLabel(graph, concept)}.`,
      action: `Redo ${conceptGraphLabel(graph, concept)} material, then attempt two questions that also use ${graph.nodes[concept]?.prereqs?.map((prereq) => conceptGraphLabel(graph, prereq)).join(" and ") || "the same setup"}.`
    }));
}

function estimateGateReadiness({ answers, conceptMastery, graph }) {
  const totalWeight = answers.reduce((sum, answer) => sum + gateQuestionWeight(answer), 0);
  const earnedWeight = answers.reduce((sum, answer) => sum + (answer.isCorrect ? gateQuestionWeight(answer) : 0), 0);
  const weightedPercent = totalWeight ? Math.round((earnedWeight / totalWeight) * 100) : 0;
  const weakCount = Object.values(conceptMastery).filter((entry) => entry.percent < 60).length;
  const adjusted = Math.max(0, weightedPercent - weakCount * 4);
  const verdict = adjusted >= 80 ? "green" : adjusted >= 60 ? "yellow" : "red";
  const chapterLabel = graph?.chapterTitle || "this chapter";
  const label = verdict === "green"
    ? `Early GATE DA readiness signal: ${adjusted}% for ${chapterLabel}.`
    : verdict === "yellow"
      ? `Early GATE DA readiness signal: ${adjusted}%; repair weak prerequisites before moving difficulty up.`
      : `Early GATE DA readiness signal: ${adjusted}%; return to core prerequisites before mixed review.`;
  return { percent: adjusted, verdict, label };
}

function gateQuestionWeight(answer) {
  const difficultyWeight = Math.max(1, Number(answer.difficulty) || 1);
  const gateWeight = answer.gateWeight === "high" ? 1.25 : answer.gateWeight === "low" ? 0.85 : 1;
  return difficultyWeight * gateWeight;
}

function buildNextQuizPlan(recommendedWork, graph = null) {
  const concepts = recommendedWork.length
    ? recommendedWork.map((item) => item.concept)
    : graph?.fallbackConcepts || ["sample-space", "event-translation", "counting"];
  return {
    dueInDays: recommendedWork.length ? 2 : 4,
    concepts,
    difficultyMix: recommendedWork.length ? [1, 1, 2, 2, 3] : graph?.fallbackDifficultyMix || [2, 2, 3, 3],
    instruction: recommendedWork.length
      ? "Retest the highest-priority weak prerequisites first, then add one mixed question."
      : graph?.fallbackInstruction || "Move to a harder mixed Chapter 1 review set."
  };
}

